const date = new Date({{system:now}});
const orgID = {{global:firstLvDeptId}};
const tenantID = {{system:tenantId}};

const yyyyMMddHH = `${date.getFullYear()}${String(date.getMonth() + 1).padStart(2, '0')}${String(date.getDate()).padStart(2, '0')}${String(date.getHours()).padStart(2, '0')}`;

return {
  redis_key: `auto_reorder:${tenantID}:${orgID}:${yyyyMMddHH}`
}

const previousData = {{workflowparams:previous_data}} || [];
const latestData = {{workflowparams:latest_data}} || [];

// Distinct item ids across previous + latest SO lines
const idSet = new Set();
[...previousData, ...latestData].forEach(item => {
  if (item && item.item_name && String(item.item_name).trim() !== "") {
    idSet.add(item.item_name);
  }
});

return { itemIDs: Array.from(idSet) };

const soPreviousData = {{workflowparams:previous_data}} || []; // array of item
const soLatestData = {{workflowparams:latest_data}} || []; // array of item (null/omitted on cancel -> [] -> negatives)
const documentType = {{workflowparams:document_type}};
let data = [];

// Item-master conversion factors (fetched once, batched, only in this SO branch)
const itemMasterRaw = {{node:search_node_SoReorderItems.data.data}} || [];
const itemMasterArr = Array.isArray(itemMasterRaw) ? itemMasterRaw : [itemMasterRaw];
const itemMasterMap = new Map();
itemMasterArr.forEach(it => { if (it && it.id) itemMasterMap.set(String(it.id), it); });

// Convert an SO line qty (in so_item_uom) to the item's base UOM qty
const convertToBaseQty = (itemId, uomId, qty) => {
  const q = parseFloat(qty) || 0;
  const itemData = itemMasterMap.get(String(itemId));
  if (!itemData || !uomId || uomId === itemData.based_uom) return q;
  const conv = Array.isArray(itemData.table_uom_conversion)
    ? itemData.table_uom_conversion.find(c => c.alt_uom_id === uomId)
    : null;
  const factor = (conv && conv.base_qty) ? parseFloat(conv.base_qty) : 1;
  return q * factor;
};

// Helper function to create composite key for maps
const getCompositeKey = (item) => {
  return `${item.item_name}|${item.plant_id}`;
};

// Helper function to aggregate items by composite key
const aggregateItems = (items) => {
  if (!items || items.length === 0) return [];

  const aggregatedMap = new Map();

  items.forEach(item => {
    // Skip items without item_name (item_id)
    if (!item.item_name || item.item_name.trim() === "") {
      return; // Skip this item
    }

    const key = getCompositeKey(item);

    // Convert so_quantity (in so_item_uom) to base UOM qty
    const quantity = convertToBaseQty(item.item_name, item.so_item_uom, item.so_quantity);

    if (aggregatedMap.has(key)) {
      // Sum up the quantity for existing key
      const existingItem = aggregatedMap.get(key);
      existingItem.so_quantity += quantity;
    } else {
      // Create new entry with a copy of the item
      aggregatedMap.set(key, {
        ...item,
        so_quantity: quantity
      });
    }
  });

  return Array.from(aggregatedMap.values());
};

// Helper to format quantity to 3 decimal places
const formatQuantity = (value) => {
  return parseFloat(value.toFixed(3));
};

// Aggregate previous and latest data
const aggregatedPrevious = aggregateItems(soPreviousData);
const aggregatedLatest = aggregateItems(soLatestData);

if (aggregatedPrevious.length > 0) {
  const previousItems = aggregatedPrevious;
  const latestItems = aggregatedLatest;

  // Create maps using composite key (item_name + plant_id)
  const previousMap = new Map(previousItems.map(item => [getCompositeKey(item), item]));
  const latestMap = new Map(latestItems.map(item => [getCompositeKey(item), item]));

  // Check for deleted and modified items
  previousItems.forEach(prevItem => {
    const compositeKey = getCompositeKey(prevItem);
    const latestItem = latestMap.get(compositeKey);

    if (!latestItem) {
      // Item deleted from that specific plant - quantity is negative (removing stock)
      data.push({
        item_id: prevItem.item_name,
        quantity: formatQuantity(-prevItem.so_quantity),
        tenant_id: {{system:tenantId}},
        organization_id: prevItem.organization_id,
        plant_id: prevItem.plant_id,
        trigger_source: documentType
      });
    } else {
      // Item exists in same plant, check for quantity changes
      const quantityDifference = formatQuantity(latestItem.so_quantity - prevItem.so_quantity);

      if (quantityDifference !== 0) {
        // Quantity changed - positive for addition, negative for removal
        data.push({
          item_id: prevItem.item_name,
          quantity: quantityDifference,
          tenant_id: {{system:tenantId}},
          organization_id: latestItem.organization_id,
          plant_id: latestItem.plant_id,
          trigger_source: documentType
        });
      }
    }
  });

  // Check for added items (new item or same item in different plant)
  latestItems.forEach(latestItem => {
    const compositeKey = getCompositeKey(latestItem);
    if (!previousMap.has(compositeKey)) {
      // New item added OR existing item moved to new plant
      data.push({
        item_id: latestItem.item_name,
        quantity: formatQuantity(latestItem.so_quantity),
        tenant_id: {{system:tenantId}},
        organization_id: latestItem.organization_id,
        plant_id: latestItem.plant_id,
        trigger_source: documentType
      });
    }
  });

} else if (aggregatedLatest.length > 0) {
  // No previous data, all items are new additions
  aggregatedLatest.forEach(latestItem => {
    data.push({
      item_id: latestItem.item_name,
      quantity: formatQuantity(latestItem.so_quantity),
      tenant_id: {{system:tenantId}},
      organization_id: latestItem.organization_id,
      plant_id: latestItem.plant_id,
      trigger_source: documentType
    });
  });
}

return { data };

const previousData = {{workflowparams:previous_data}} || []; // array of item
const latestData = {{workflowparams:latest_data}} || []; // array of item (null/omitted on cancel -> [] -> negatives)
const documentType = {{workflowparams:document_type}};
let data = [];

// Helper to extract and aggregate temp_qty_data
const extractTempQtyData = (items) => {
  if (!items || items.length === 0) return [];

  const aggregatedMap = new Map();

  items.forEach(item => {
    if (!item.temp_qty_data) return;

    let tempQtyArray = item.temp_qty_data;

    // Parse if it's a string
    if (typeof tempQtyArray === 'string') {
      try {
        tempQtyArray = JSON.parse(tempQtyArray);
      } catch (e) {
        console.error('Failed to parse temp_qty_data:', e);
        return;
      }
    }

    if (!Array.isArray(tempQtyArray)) return;

    // Convert this line's allocations from order UOM to base UOM.
    // The GD line carries both gd_qty (order UOM) and base_qty (base UOM),
    // so the factor is derivable per line with no item-master fetch.
    const lineGdQty = parseFloat(item.gd_qty) || 0;
    const lineBaseQty = parseFloat(item.base_qty) || 0;
    const lineFactor = (lineGdQty > 0 && lineBaseQty > 0) ? (lineBaseQty / lineGdQty) : 1;

    tempQtyArray.forEach(qtyItem => {
      const materialId = qtyItem.material_id;
      const locationId = qtyItem.location_id;

      if (!materialId || !locationId) return;

      const key = `${materialId}|${locationId}`;
      const gdQuantity = (parseFloat(qtyItem.gd_quantity) || 0) * lineFactor;

      if (aggregatedMap.has(key)) {
        aggregatedMap.get(key).gd_quantity += gdQuantity;
      } else {
        aggregatedMap.set(key, {
          material_id: materialId,
          location_id: locationId,
          plant_id: qtyItem.plant_id,
          organization_id: qtyItem.organization_id,
          gd_quantity: gdQuantity,
          batch_id: qtyItem.batch_id
        });
      }
    });
  });

  return Array.from(aggregatedMap.values());
};

// Helper to format quantity
const formatQuantity = (value) => {
  return Math.round(value * 1000) / 1000; // Keep 3 decimal places
};

// Get composite key
const getKey = (item) => `${item.material_id}|${item.location_id}`;

// Extract and aggregate
const prevAggregated = extractTempQtyData(previousData);
const latestAggregated = extractTempQtyData(latestData);

// Create maps
const prevMap = new Map(prevAggregated.map(item => [getKey(item), item]));
const latestMap = new Map(latestAggregated.map(item => [getKey(item), item]));

// Process all keys
const allKeys = new Set([...prevMap.keys(), ...latestMap.keys()]);

allKeys.forEach(key => {
  const prevItem = prevMap.get(key);
  const latestItem = latestMap.get(key);

  if (prevItem && !latestItem) {
    // Item removed from location
    data.push({
      item_id: prevItem.material_id,
      quantity: formatQuantity(-prevItem.gd_quantity),
      tenant_id: {{system:tenantId}},
      organization_id: prevItem.organization_id,
      plant_id: prevItem.plant_id,
      location_id: prevItem.location_id,
      trigger_source: documentType
    });
  } 
  else if (!prevItem && latestItem) {
    // New item added to location
    data.push({
      item_id: latestItem.material_id,
      quantity: formatQuantity(latestItem.gd_quantity),
      tenant_id: {{system:tenantId}},
      organization_id: latestItem.organization_id,
      plant_id: latestItem.plant_id,
      location_id: latestItem.location_id,
      trigger_source: documentType
    });
  }
  else if (prevItem && latestItem && prevItem.gd_quantity !== latestItem.gd_quantity) {
    // Quantity changed
    const difference = formatQuantity(latestItem.gd_quantity - prevItem.gd_quantity);
    if (difference !== 0) {
      data.push({
        item_id: prevItem.material_id,
        quantity: difference,
        tenant_id: {{system:tenantId}},
        organization_id: latestItem.organization_id,
        plant_id: latestItem.plant_id,
        location_id: latestItem.location_id,
        trigger_source: documentType
      });
    }
  }
});

return { data };

