const previousData = {{workflowparams:previous_data}} || [];
const latestData = {{workflowparams:latest_data}} || [];

// A Category Transfer moves stock between inventory categories at the SAME
// plant + location. Availability only changes when Unrestricted is one side:
//   Unrestricted -> non-Unrestricted  => +qty (available drops)
//   non-Unrestricted -> Unrestricted  => -qty (available rises)
//   neither side Unrestricted         =>  0   (skip entirely)
// NOTE: CAT allocations carry category_from / category_to — there is NO
// `category` key (unlike MSI/PT), so the MSI filter must NOT be reused here.
const isU = (c) => c === 'Unrestricted';
const signOf = (a) => {
  const from = isU(a.category_from);
  const to = isU(a.category_to);
  if (from && !to) return 1;
  if (!from && to) return -1;
  return 0;
};

// Only allocations that actually shift availability need a conversion factor.
const idSet = new Set();
const collectIds = (lines) => {
  lines.forEach(line => {
    let tqd = line.temp_qty_data;
    if (typeof tqd === 'string') { try { tqd = JSON.parse(tqd); } catch (e) { return; } }
    if (!Array.isArray(tqd)) return;
    tqd.forEach(a => { if (a && a.material_id && signOf(a) !== 0) idSet.add(a.material_id); });
  });
};
collectIds(previousData);
collectIds(latestData);

return { itemIDs: Array.from(idSet) };

